function base64UrlDecode(input) {
  const normalized = input.replace(/-/g, "+").replace(/_/g, "/");
  const padded = normalized + "=".repeat((4 - (normalized.length % 4)) % 4);
  return decodeURIComponent(
    atob(padded)
      .split("")
      .map((c) => `%${("00" + c.charCodeAt(0).toString(16)).slice(-2)}`)
      .join("")
  );
}

function decodeJwt(token) {
  if (!token) return null;
  const parts = token.split(".");
  if (parts.length < 2) return null;
  try {
    return JSON.parse(base64UrlDecode(parts[1]));
  } catch {
    return null;
  }
}

function randomString(length = 64) {
  const chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789-._~";
  const array = new Uint8Array(length);
  crypto.getRandomValues(array);
  return Array.from(array, (x) => chars[x % chars.length]).join("");
}

async function sha256(input) {
  const data = new TextEncoder().encode(input);
  const digest = await crypto.subtle.digest("SHA-256", data);
  return new Uint8Array(digest);
}

function base64UrlEncodeBytes(bytes) {
  let binary = "";
  bytes.forEach((b) => {
    binary += String.fromCharCode(b);
  });
  return btoa(binary).replace(/\+/g, "-").replace(/\//g, "_").replace(/=+$/g, "");
}

async function createPkcePair() {
  const codeVerifier = randomString(96);
  const hashed = await sha256(codeVerifier);
  const codeChallenge = base64UrlEncodeBytes(hashed);
  return { codeVerifier, codeChallenge };
}

function saveAuth(data) {
  localStorage.setItem("oidc_auth", JSON.stringify(data));
}

function loadAuth() {
  const raw = localStorage.getItem("oidc_auth");
  if (!raw) return null;
  try {
    return JSON.parse(raw);
  } catch {
    return null;
  }
}

function clearAuth() {
  localStorage.removeItem("oidc_auth");
}

function saveTransaction(data) {
  sessionStorage.setItem("oidc_tx", JSON.stringify(data));
}

function loadTransaction() {
  const raw = sessionStorage.getItem("oidc_tx");
  if (!raw) return null;
  try {
    return JSON.parse(raw);
  } catch {
    return null;
  }
}

function clearTransaction() {
  sessionStorage.removeItem("oidc_tx");
}

async function exchangeCodeForTokens(code, codeVerifier) {
  const body = new URLSearchParams({
    grant_type: "authorization_code",
    code,
    redirect_uri: OIDC_CONFIG.redirectUri,
    client_id: OIDC_CONFIG.clientId,
    code_verifier: codeVerifier
  });

  const response = await fetch(OIDC_CONFIG.tokenEndpoint, {
    method: "POST",
    headers: {
      "Content-Type": "application/x-www-form-urlencoded"
    },
    body: body.toString()
  });

  if (!response.ok) {
    const text = await response.text();
    throw new Error(`Token exchange failed: ${response.status} ${text}`);
  }

  return response.json();
}

const AuthContext = createContext(null);

function AuthProvider({ children }) {
  const [tokens, setTokens] = useState(() => loadAuth());
  const [loading, setLoading] = useState(false);

  const user = useMemo(() => decodeJwt(tokens?.id_token), [tokens]);

  const login = async () => {
    setLoading(true);
    try {
      const state = randomString(32);
      const nonce = randomString(32);
      const { codeVerifier, codeChallenge } = await createPkcePair();

      saveTransaction({ state, nonce, codeVerifier });

      const params = new URLSearchParams({
        client_id: OIDC_CONFIG.clientId,
        redirect_uri: OIDC_CONFIG.redirectUri,
        response_type: OIDC_CONFIG.responseType,
        scope: OIDC_CONFIG.scope,
        state,
        nonce,
        code_challenge: codeChallenge,
        code_challenge_method: "S256"
      });

      window.location.assign(`${OIDC_CONFIG.authorizationEndpoint}?${params.toString()}`);
    } finally {
      setLoading(false);
    }
  };

  const logout = () => {
    clearAuth();
    clearTransaction();
    setTokens(null);
    window.history.replaceState({}, document.title, "/");
  };

  const handleCallback = async () => {
    setLoading(true);
    try {
      const url = new URL(window.location.href);
      const code = url.searchParams.get("code");
      const returnedState = url.searchParams.get("state");
      const error = url.searchParams.get("error");
      const errorDescription = url.searchParams.get("error_description");

      if (error) {
        throw new Error(`${error}: ${errorDescription || "Authorization failed"}`);
      }

      if (!code) {
        throw new Error("Missing authorization code");
      }

      const tx = loadTransaction();
      if (!tx) {
        throw new Error("Missing authentication transaction");
      }

      if (tx.state !== returnedState) {
        throw new Error("Invalid state");
      }

      const tokenResponse = await exchangeCodeForTokens(code, tx.codeVerifier);
      const profile = decodeJwt(tokenResponse.id_token);

      if (profile?.nonce && profile.nonce !== tx.nonce) {
        throw new Error("Invalid nonce");
      }

      const authData = {
        ...tokenResponse,
        profile,
        obtained_at: Math.floor(Date.now() / 1000)
      };

      saveAuth(authData);
      setTokens(authData);
      clearTransaction();
      window.history.replaceState({}, document.title, "/");
    } finally {
      setLoading(false);
    }
  };

  return (
    <AuthContext.Provider
      value={{
        tokens,
        user,
        loading,
        isAuthenticated: !!tokens?.id_token,
        login,
        logout,
        handleCallback
      }}
    >
      {children}
    </AuthContext.Provider>
  );
}

function useAuth() {
  const ctx = useContext(AuthContext);
  if (!ctx) throw new Error("useAuth must be used within AuthProvider");
  return ctx;
}

function HomePage() {
  const { isAuthenticated, user, tokens, login, logout, loading } = useAuth();

  return (
    <div style={{ fontFamily: "Arial, sans-serif", padding: 24 }}>
      <h1>OIDC SPA Authentication</h1>

      {!isAuthenticated ? (
        <div>
          <p>You are not logged in.</p>
          <button onClick={login} disabled={loading}>
            {loading ? "Redirecting..." : "Login"}
          </button>
        </div>
      ) : (
        <div>
          <p>Authenticated successfully.</p>
          <button onClick={logout}>Logout</button>

          <h2>User Profile</h2>
          <pre>{JSON.stringify(user, null, 2)}</pre>

          <h2>Tokens</h2>
          <pre>{JSON.stringify(tokens, null, 2)}</pre>
        </div>
      )}
    </div>
  );
}

function CallbackPage() {
  const { handleCallback, loading } = useAuth();
  const [error, setError] = useState("");

  useEffect(() => {
    handleCallback().catch((e) => {
      setError(e.message || "Callback handling failed");
    });
  }, [handleCallback]);

  return (
    <div style={{ fontFamily: "Arial, sans-serif", padding: 24 }}>
      <h1>Signing you in...</h1>
      {loading && !error && <p>Processing authorization response...</p>}
      {error && (
        <div>
          <p>Authentication error:</p>
          <pre>{error}</pre>
        </div>
      )}
    </div>
  );
}

function AppRouter() {
  const path = window.location.pathname;
  if (path === "/callback") {
    return <CallbackPage />;
  }
  return <HomePage />;
}

function App() {
  return (
    <AuthProvider>
      <AppRouter />
    </AuthProvider>
  );
}

const rootElement = document.getElementById("root");
createRoot(rootElement).render(<App />);